UIFriendApplyItem = class("UIFriendApplyItem", IGUIWindow)

function UIFriendApplyItem:onLoad()
    print("UIFriendApplyItem:onLoad()")
    self.icon = self:getChildWindow(0 , GUIType.UrlImage)
    self.icon:setDefaultImage("set:userItem.json image:icon")
    self.name = self:getChildWindow(1)
    self.sex = self:getChildWindow(2, GUIType.StaticImage)
    self.status = self:getChildWindow(3)
    self.text = self:getChildWindow(4)
    self.refuseBtn = self:getChildWindow(5):GetChildByIndex(0)
    self.refuseBtn:registerEvent(GUIEvent.ButtonClick, function()
        self:onRefuseButtonEvent()
    end)
    self.agreeBtn = self:getChildWindow(5):GetChildByIndex(1)
    self.agreeBtn:registerEvent(GUIEvent.ButtonClick, function()
        self:onAgreeButtonEvent()
    end)
    self.data = {}
end

function UIFriendApplyItem:onRefuseButtonEvent()
    print("onRefuseButton")
    MultiBuildData:postRejectionFriend(self.data.userId)
end

function UIFriendApplyItem:onAgreeButtonEvent()
    print("onAgreeButton")
    MultiBuildData:postAgreementFriend(self.data.userId)
end

function UIFriendApplyItem:getStatusText()
    if self.data.onlineStatus == 20 then
        if self.data.gameId == BaseMain:getGameType() then
            return Lang:getString("online")
        end
    end
    return Lang:getString("offline")
end

function UIFriendApplyItem:getSexIcon()
    if self.data.sex == 2 then
        return "set:skyblock_friend.json image:sex_girl"
    end
    return "set:skyblock_friend.json image:sex_boy"
end

function UIFriendApplyItem:setItemData(data)
    print("UIFriendApplyItem setItemData")
    self.data = data
    self:setDataUpdate()
end

function UIFriendApplyItem:setDataUpdate()
    if self.data.picUrl then
        self.icon:setUrl(self.data.picUrl)
    end
    self.name:SetText(self.data.nickName)
    self.status:SetText(self:getStatusText())
    self.sex:SetImage(self:getSexIcon())
    self.text:SetText(Lang:getString("apply_friend_text"))
end